import React, { useState, useContext, Suspense } from 'react';
import { SectionHeading } from '@/components/ui/Typography';
import { Box, Button, Stack, TextField } from '@mui/material';
import { PageCard } from '@/components/PageCard';
import LockOpenIcon from '@mui/icons-material/LockOpen';
import NumbersIcon from '@mui/icons-material/Numbers';
import { EnvConfig } from '@/constants/EnvConfig';
import { useNavigate, useSearch } from '@tanstack/react-router';
import { CallStatus, Validator } from '@/types/api.types';
import { SetAccessTokenData } from '@/utils/token';
import { AuthContext } from '@/contexts/AuthContext';
import { AuthTokenResult, CreateOtpPayload, CreateTokenPayload } from '@/types/auth.types';
import { Pathname } from '@/constants/Routes';
import { AuthServices, AuthServicesError } from '@/api';
// next/image removed - use <img> instead
import { StatusMessage } from '@/components/StatusMessage';
import { initialStateData, StateData } from '@/store';
import { ApiComponentStateManager } from '@/lib/api-state';

const alignSelfCenter: React.CSSProperties = {
    alignSelf: 'center'
};

const LoginContent: React.FC = () => {
    const { setAuthData } = useContext(AuthContext);
    const [sendOtp, setSendOtp] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [requestToken, setRequestToken] = React.useState<StateData<AuthTokenResult>>(initialStateData<AuthTokenResult>());
    const [formData, setFormData] = useState<CreateTokenPayload>({ emailOrPhone: '', otp: '' });
    const [redirectUrl, setRedirectUrl] = useState<string>(Pathname.Root);
    const [isRedirecting, setIsRedirecting] = useState(false);

    const navigate = useNavigate();
    const search = useSearch({ strict: false }) as Record<string, string>;

    // Handle redirect URL after component mounts to avoid hydration issues
    React.useEffect(() => {
        const redirect = search?.redirect || Pathname.Root;
        setRedirectUrl(redirect);
    }, [search]);

    React.useEffect(() => {
        if (requestToken.status === CallStatus.Success && requestToken.data.accessToken) {
            SetAccessTokenData(requestToken.data);
            setAuthData({ name: requestToken.data.name, email: requestToken.data.resource });
            setIsRedirecting(true);
            window.dispatchEvent(new Event('auth-changed'));
            if (!requestToken.data.xv) {
                // Profile incomplete: forward the original redirect so it can be honored after profile completion.
                navigate({
                    to: Pathname.Profile_Edit as string,
                    search: { redirect: redirectUrl },
                    replace: true,
                });
            } else {
                navigate({ to: redirectUrl, replace: true });
            }
        }
    }, [requestToken.status, redirectUrl, navigate]);

    if (isRedirecting) {
        return null;
    }

    const handleGetOtpClick = () => {
        const payload: CreateOtpPayload = { emailOrPhone: formData.emailOrPhone };
        ApiComponentStateManager(AuthServices.CreateOtp(payload), setSendOtp);
    };

    const handleLoginClick = () => {
        const payload: CreateTokenPayload = { emailOrPhone: formData.emailOrPhone, otp: formData.otp };
        ApiComponentStateManager(AuthServices.CreateToken(payload), setRequestToken);
    }

    return (
        <Stack direction='column' sx={{ alignItems: 'center', justifyContent: 'center', height: '80vh' }}>
            <PageCard>
                <form onSubmit={(e) => { e.preventDefault(); handleLoginClick(); }}>
                    <Stack
                        direction='column'
                        sx={{ alignContent: 'center', justifyContent: 'center', margin: 2 }}
                        spacing={2}
                    >
                        <img
                            src={EnvConfig.SiteLogo}
                            alt='Logo'
                            width={100}
                            height={100}
                            style={alignSelfCenter}
                        />
                        <SectionHeading sx={{ textAlign: 'center' }}>Login to Portal</SectionHeading>
                        <TextField
                            id='email'
                            label='Email'
                            variant='outlined'
                            value={formData.emailOrPhone}
                            required
                            inputMode='email'
                            onChange={(e) => { setFormData((prev) => ({ ...prev, emailOrPhone: e.target.value })) }}
                            error={formData.emailOrPhone !== "" && !Validator.IsEmail(formData.emailOrPhone)}
                        />
                        <TextField
                            id='otp'
                            label='OTP'
                            variant='outlined'
                            value={formData.otp}
                            inputMode='numeric'
                            required
                            onChange={(e) => { setFormData((prev) => ({ ...prev, otp: e.target.value })) }}
                            error={formData.otp !== "" && (formData.otp.length !== 6 || !Validator.IsNumber(formData.otp))}
                        />
                        <Stack direction='row' sx={{ justifyContent: 'center' }} spacing={2}>
                            <Button
                                variant='outlined'
                                endIcon={<NumbersIcon />}
                                disabled={!Validator.IsEmail(formData.emailOrPhone)}
                                onClick={handleGetOtpClick}
                            >
                                Get OTP
                            </Button>
                            <Button
                                type='submit'
                                variant='contained'
                                endIcon={<LockOpenIcon />}
                                disabled={!Validator.IsEmail(formData.emailOrPhone) || !Validator.IsNumber(formData.otp) || formData.otp.length !== 6}
                                onClick={handleLoginClick}
                            >
                                Login
                            </Button>
                        </Stack>
                    </Stack>
                </form>
            </PageCard>
            {
                !isRedirecting && (
                requestToken.status === CallStatus.NotStarted ? (
                    <StatusMessage
                        style={{ marginTop: 0 }}
                        notStartedMessage='Enter your credential to login.'
                        successMessage='OTP sent successfully.'
                        failureMessage={AuthServicesError.CreateOtpError(sendOtp.httpStatus)}
                        currentStatus={sendOtp.status}
                        correlationId={sendOtp.correlationId}
                    />
                ) : requestToken.status !== CallStatus.Success ? (
                    <StatusMessage
                        style={{ marginTop: 0 }}
                        notStartedMessage='Please enter email and OTP.'
                        failureMessage={AuthServicesError.CreateTokenError(requestToken.httpStatus)}
                        currentStatus={requestToken.status}
                        correlationId={requestToken.correlationId}
                    />
                ) : null
                )
            }
        </Stack>
    );
};

export const Login: React.FC = () => {
    return (
        <Suspense fallback={<Box sx={{ display: 'flex', justifyContent: 'center', p: 2.5 }}>Loading...</Box>}>
            <LoginContent />
        </Suspense>
    );
};

